={{ (function() {
  if ($json.body.test === true) return true;
  var pickup = $json.body.pickup_time || 'ASAP';
  var now = new Date();
  var cst = new Date(now.toLocaleString('en-US', { timeZone: 'America/Chicago' }));
  var day = cst.getDay();
  var hour = cst.getHours();
  var min = cst.getMinutes();
  var isWeekday = day >= 1 && day <= 6;
  if (!isWeekday) return false;
  var openMin = 12 * 60 + 30;
  var closeMin = 19 * 60 + 30;
  if (pickup === 'ASAP') {
    var currentMin = hour * 60 + min;
    var asapMin = currentMin + 30;
    return asapMin >= openMin && asapMin <= closeMin;
  } else {
    var parts = pickup.split(':');
    var pHour = parseInt(parts[0]);
    var pMin = parseInt(parts[1]);
    var pickupMin = pHour * 60 + pMin;
    return pickupMin >= openMin && pickupMin <= closeMin;
  }
})() }}

