const validated = $('Validate & Calculate').first().json;
const squareResponse = $input.first().json;

const paymentLink = squareResponse.payment_link || {};
const orderId =
  paymentLink.order_id ||
  squareResponse.order_id ||
  (squareResponse.related_resources && squareResponse.related_resources.orders && squareResponse.related_resources.orders[0] && squareResponse.related_resources.orders[0].id) ||
  '';

return [{
  json: {
    ...validated,
    square_response: squareResponse,
    square_link: paymentLink.url || paymentLink.long_url || '',
    square_order_id: orderId
  }
}];

const merged = $json;

return [{
  json: {
    ok: true,
    success: true,
    message: 'We Got You! Follow the link below to complete your secure payment. We will begin preparing your order once payment is complete.',
    square_link: merged.square_link || '',
    payment_link: merged.square_link || '',
    payment_url: merged.square_link || '',
    order_id: merged.order_id,
    total_cents: merged.total_cents,
    subtotal_cents: merged.subtotal_cents,
    tax_cents: merged.tax_cents,
    frontend_mismatch: merged.frontend_mismatch || false
  }
}];

const merged = $json;
const dbPath = '/Users/philliplowe/.openclaw/workspaces/sol/utopia-deli-revamp/orders.db';
const sqlite3 = require('sqlite3').verbose();

return new Promise((resolve) => {
  const db = new sqlite3.Database(dbPath, (err) => {
    if (err) {
      resolve([{ json: { db_saved: false, db_error: err.message } }]);
      return;
    }

    const paymentLink = merged.payment_link || merged.square_link || '';
    const customer = merged.customer || {};

    db.run(
      `INSERT INTO orders (
        order_id, customer_name, customer_email, customer_phone,
        customer_city, customer_county, cart_json,
        subtotal_cents, tax_cents, total_cents,
        square_payment_link, square_order_id,
        notes, status, source, email_sent
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
      [
        merged.order_id,
        customer.name || '',
        customer.email || '',
        customer.phone || '',
        customer.city || 'Little Rock',
        customer.county || '',
        JSON.stringify(merged.items),
        merged.subtotal_cents,
        merged.tax_cents,
        merged.total_cents,
        paymentLink,
        merged.square_order_id || '',
        merged.notes || '',
        'pending',
        'pickup-order',
        0
      ],
      function(err) {
        if (err) {
          resolve([{ json: { db_saved: false, db_error: err.message } }]);
        } else {
          resolve([{ json: { db_saved: true, db_rowid: this.lastID } }]);
        }
        db.close();
      }
    );
  });
});

return [{
  json: {
    ok: false,
    success: false,
    code: 'DELI_CLOSED',
    error: 'We are currently closed or outside pickup hours.',
    message: 'Pickup hours are Monday-Saturday, 12:30 PM – 7:30 PM. Please try again during business hours.'
  }
}];
